def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  queries.map { case Array(l, r, threshold) =>
    val subArray = nums.slice(l.toInt, r.toInt + 1)
    val frequencyMap = subArray.groupBy(identity).mapValues(_.length)
    val filtered = frequencyMap.filter { case (_, cnt) => cnt >= threshold }
    if (filtered.isEmpty) {
      -1L
    } else {
      val maxFreq = filtered.values.max
      val candidates = filtered.filter(_._2 == maxFreq).keys.toList
      candidates.min
    }
  }
}
